import numpy as np

def select_next_node(current_node, truck_nodes, destination_node, unvisited_nodes, distance_matrix):
    max_ratio = -np.inf
    next_node = None

    for node in unvisited_nodes:
        total_distance_to_trucks = np.sum([distance_matrix[truck_node][node] for truck_node in truck_nodes])
        is_reachable = any([distance_matrix[truck_node][node] < np.inf for truck_node in truck_nodes])
        if is_reachable:
            distance_to_next_node = distance_matrix[current_node][node]
            if distance_to_next_node > 0:
                ratio = total_distance_to_trucks / distance_to_next_node
                if ratio > max_ratio:
                    max_ratio = ratio
                    next_node = node

    return next_node
